<template>
  <b-field :label="assetAdded" :addons="false" class="info">
    <b-tooltip label="Please list all assets in your possession." position="is-left" size="is-medium" type="is-dark" animated multilined v-once>
      <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
    </b-tooltip>
    <b-field>
      <b-input v-model="assetType" type="text" :icon="typeIcon" style="flex:3;" placeholder="I own"></b-input>
      <b-input v-model="assetValue" :icon="valueIcon" style="flex:2;" placeholder="CAD"></b-input>
      <span class="control">
        <button class="button is-outlined is-primary" v-if="adding" :disabled="empty" @click="addField">
          <i class="fas fa-plus"></i>&ensp;Add</button>
        <button class="button is-outlined is-danger" v-else @click="removeField">
          <i class="fas fa-minus"></i>&ensp;Remove</button>
      </span>
    </b-field>
  </b-field>
</template>

<script>
export default {
  methods: {
    addField() {
      if (this.assetType.length > 2 && this.assetValue.length > 2) {
        if (this.$store.state.AssetsLiabilitiesForm.assets.length < 6) {
          this.$store.dispatch("addAsset", {
            type: this.assetType,
            value: this.assetValue
          });
          this.$store.dispatch("clearField", "assets");
        }
      }
    },
    removeField() {
      if (this.$store.state.AssetsLiabilitiesForm.assets.length > 1) {
        this.$store.dispatch("removeAsset", {
          type: this.assetType,
          value: this.assetValue
        });
      }
    }
  },
  computed: {
    empty() {
      return this.assetType.length < 2 && this.assetValue.length < 2;
    },
    full() {
      return this.$store.state.AssetsLiabilitiesForm.assets.length === 5;
    },
    noAssets() {
      return this.$store.state.AssetsLiabilitiesForm.assets.length === 0;
    },
    assetType: {
      get() {
        return this.$store.state.AssetsLiabilitiesForm.assets[this.ind].type;
      },
      set(val) {
        this.$store.state.AssetsLiabilitiesForm.assets[this.ind].type = val;
      }
    },
    assetValue: {
      get() {
        return this.$store.state.AssetsLiabilitiesForm.assets[this.ind].value;
      },
      set(val) {
        this.$store.state.AssetsLiabilitiesForm.assets[this.ind].value = val;
      }
    },
    adding() {
      return this.ind > 0 ? false : true;
    },
    assetAdded() {
      return this.adding ? 'Asset' : 'Asset added';
    },
    typeIcon() {
      if (this.adding) {
        return 'credit-card';
      } else {
        return 'check-square'
      }
    },
    valueIcon() {
      if (this.adding) {
        return 'dollar-sign';
      } else {
        return 'check-square'
      }
    }
  },
  props: {
    ind: Number
  }
};
</script>